class MKAverage {
    int m, k;
    deque<int> dq;
    vector<int> lastM;
public:
    MKAverage(int m, int k) : m(m), k(k) {}

    void addElement(int num) {
        dq.push_back(num);
        if (dq.size() > m) dq.pop_front();
    }

    int calculateMKAverage() {
        if (dq.size() < m) return -1;
        lastM.assign(dq.begin(), dq.end());
        nth_element(lastM.begin(), lastM.begin() + k, lastM.end());
        nth_element(lastM.begin() + k, lastM.end() - k, lastM.end());
        long long sum = 0;
        for (int i = k; i < m - k; ++i) sum += lastM[i];
        return static_cast<int>(sum / (m - 2 * k));
    }
};
```
efficiency: HIGH
time complexity: O(m) per calculateMKAverage, O(1) per addElement
space complexity: O(m)
energy implications: LOW
explanation: Uses a deque to maintain the last m elements in O(1) per addElement. On calculateMKAverage, copies the last m elements into a vector, uses nth_element twice to partition out the smallest k and largest k elements in linear time, then sums the middle m-2k elements. Efficient for the given constraints.

